import { mkdir, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { build } from "vite";

const packageDir = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const entry = resolve(packageDir, "src/tree/mcp-shim/entry.tsx");
const output = resolve(packageDir, "../mcp/src/shim/shim-html.gen.ts");

const result = await build({
  configFile: false,
  root: packageDir,
  define: { "process.env.NODE_ENV": JSON.stringify("production") },
  build: {
    write: false,
    minify: "esbuild",
    target: "es2020",
    lib: {
      entry,
      name: "VendoMcpAppShim",
      formats: ["iife"],
      fileName: () => "vendo-mcp-app-shim.js",
    },
    rollupOptions: {
      output: { inlineDynamicImports: true },
    },
  },
});

const outputs = Array.isArray(result) ? result.flatMap((entryResult) => entryResult.output) : result.output;
const chunk = outputs.find((item) => item.type === "chunk");
if (!chunk || chunk.type !== "chunk") throw new Error("Vite did not emit the MCP Apps shim chunk");

const script = chunk.code
  .replace(/^\/\/[#@] sourceMappingURL=.*$/gm, "")
  .replace(/^\/\/.*bundle hash:.*$/gim, "")
  .replace(/<\/script/gi, "<\\/script")
  .trim();
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Vendo app</title>
  <style>
    :root { color-scheme: light dark; font-family: system-ui, sans-serif; }
    * { box-sizing: border-box; }
    body { margin: 0; padding: 12px; background: transparent; color: var(--color-text-primary, #1a1a1e); }
    #vendo-mcp-shim { min-width: 0; }
    [role="note"] { margin-top: 8px; }
  </style>
</head>
<body>
  <main id="vendo-mcp-shim" aria-live="polite"></main>
  <script>${script}</script>
</body>
</html>`;

await mkdir(dirname(output), { recursive: true });
await writeFile(
  output,
  `/**
 * Generated by packages/ui/scripts/build-mcp-app-shim.mjs. Do not edit.
 *
 * Regenerate: pnpm --filter @vendoai/ui build:mcp-shim
 */
export const SHIM_HTML: string = ${JSON.stringify(html)};\n`,
  "utf8",
);
console.log(`[ui] generated MCP Apps shim (${html.length} bytes)`);
